3	namespace Illuminate\Foundation\Http;
4	
5	use Carbon\CarbonInterval;
6	use DateTimeInterface;
7	use Illuminate\Contracts\Debug\ExceptionHandler;
8	use Illuminate\Contracts\Foundation\Application;
9	use Illuminate\Contracts\Http\Kernel as KernelContract;
10	use Illuminate\Foundation\Events\Terminating;
11	use Illuminate\Foundation\Http\Events\RequestHandled;
12	use Illuminate\Routing\Pipeline;
13	use Illuminate\Routing\Router;
14	use Illuminate\Support\Carbon;
15	use Illuminate\Support\Facades\Request;
16	use Illuminate\Support\InteractsWithTime;
17	use InvalidArgumentException;
18	use Throwable;
19	
20	class Kernel implements KernelContract
21	{
22	    use InteractsWithTime;
23	
24	    /**
25	     * The application implementation.
26	     *
27	     * @var \Illuminate\Contracts\Foundation\Application
28	     */
29	    protected $app;
30	
31	    /**
32	     * The router instance.
33	     *
34	     * @var \Illuminate\Routing\Router
35	     */
36	    protected $router;
37	
38	    /**
39	     * The bootstrap classes for the application.
40	     *
41	     * @var string[]
42	     */
43	    protected $bootstrappers = [
44	        \Illuminate\Foundation\Bootstrap\LoadEnvironmentVariables::class,
45	        \Illuminate\Foundation\Bootstrap\LoadConfiguration::class,
46	        \Illuminate\Foundation\Bootstrap\HandleExceptions::class,
47	        \Illuminate\Foundation\Bootstrap\RegisterFacades::class,
48	        \Illuminate\Foundation\Bootstrap\RegisterProviders::class,
49	        \Illuminate\Foundation\Bootstrap\BootProviders::class,
50	    ];
51	
52	    /**
53	     * The application's middleware stack.
54	     *
55	     * @var array<int, class-string|string>
56	     */
57	    protected $middleware = [];
58	
59	    /**
60	     * The application's route middleware groups.
61	     *
62	     * @var array<string, array<int, class-string|string>>
63	     */
64	    protected $middlewareGroups = [];
65	
66	    /**
67	     * The application's route middleware.
68	     *
69	     * @var array<string, class-string|string>
70	     *
71	     * @deprecated
72	     */
73	    protected $routeMiddleware = [];
74	
75	    /**
76	     * The application's middleware aliases.
77	     *
78	     * @var array<string, class-string|string>
79	     */
80	    protected $middlewareAliases = [];
81	
82	    /**
83	     * All of the registered request duration handlers.
84	     *
85	     * @var array
86	     */
87	    protected $requestLifecycleDurationHandlers = [];
88	
89	    /**
90	     * When the kernel starting handling the current request.
91	     *
92	     * @var \Illuminate\Support\Carbon|null
93	     */
94	    protected $requestStartedAt;
95	
96	    /**
97	     * The priority-sorted list of middleware.
98	     *
99	     * Forces non-global middleware to always be in the given order.
100	     *
101	     * @var string[]
102	     */
103	    protected $middlewarePriority = [
104	        \Illuminate\Foundation\Http\Middleware\HandlePrecognitiveRequests::class,
105	        \Illuminate\Cookie\Middleware\EncryptCookies::class,
106	        \Illuminate\Cookie\Middleware\AddQueuedCookiesToResponse::class,
107	        \Illuminate\Session\Middleware\StartSession::class,
108	        \Illuminate\View\Middleware\ShareErrorsFromSession::class,
109	        \Illuminate\Contracts\Auth\Middleware\AuthenticatesRequests::class,
110	        \Illuminate\Routing\Middleware\ThrottleRequests::class,
111	        \Illuminate\Routing\Middleware\ThrottleRequestsWithRedis::class,
112	        \Illuminate\Contracts\Session\Middleware\AuthenticatesSessions::class,
113	        \Illuminate\Routing\Middleware\SubstituteBindings::class,
114	        \Illuminate\Auth\Middleware\Authorize::class,
115	    ];
116	
117	    /**
118	     * Create a new HTTP kernel instance.
119	     *
120	     * @param  \Illuminate\Contracts\Foundation\Application  $app
121	     * @param  \Illuminate\Routing\Router  $router
122	     */
123	    public function __construct(Application $app, Router $router)
124	    {
125	        $this->app = $app;
126	        $this->router = $router;
127	
128	        $this->syncMiddlewareToRouter();
129	    }
130	
131	    /**
132	     * Handle an incoming HTTP request.
133	     *
134	     * @param  \Illuminate\Http\Request  $request
135	     * @return \Illuminate\Http\Response
136	     */
137	    public function handle($request)
138	    {
139	        $this->requestStartedAt = Carbon::now();
140	
141	        try {
142	            $request->enableHttpMethodParameterOverride();
143	
144	            $response = $this->sendRequestThroughRouter($request);
145	        } catch (Throwable $e) {
146	            $this->reportException($e);
147	
148	            $response = $this->renderException($request, $e);
149	        }
150	
151	        $this->app['events']->dispatch(
152	            new RequestHandled($request, $response)
153	        );
154	
155	        return $response;
156	    }
157	
158	    /**
159	     * Send the given request through the middleware / router.
160	     *
161	     * @param  \Illuminate\Http\Request  $request
162	     * @return \Illuminate\Http\Response
163	     */
164	    protected function sendRequestThroughRouter($request)
165	    {
166	        $this->app->instance('request', $request);
167	
168	        Request::clearResolvedInstance();
169	
170	        $this->bootstrap();
171	
172	        return (new Pipeline($this->app))
173	            ->send($request)
174	            ->through($this->app->shouldSkipMiddleware() ? [] : $this->middleware)
175	            ->then($this->dispatchToRouter());
176	    }
177	
178	    /**
179	     * Bootstrap the application for HTTP requests.
180	     *
181	     * @return void
182	     */
183	    public function bootstrap()
184	    {
185	        if (! $this->app->hasBeenBootstrapped()) {
186	            $this->app->bootstrapWith($this->bootstrappers());
187	        }
188	    }
189	
190	    /**
191	     * Get the route dispatcher callback.
192	     *
193	     * @return \Closure
194	     */
195	    protected function dispatchToRouter()
196	    {
197	        return function ($request) {
198	            $this->app->instance('request', $request);
199	
200	            return $this->router->dispatch($request);
201	        };
202	    }
203	
204	    /**
205	     * Call the terminate method on any terminable middleware.
206	     *
207	     * @param  \Illuminate\Http\Request  $request
208	     * @param  \Illuminate\Http\Response  $response
209	     * @return void
210	     */
211	    public function terminate($request, $response)
212	    {
213	        $this->app['events']->dispatch(new Terminating);
214	
215	        $this->terminateMiddleware($request, $response);
216	
217	        $this->app->terminate();
218	
219	        if ($this->requestStartedAt === null) {
220	            return;
221	        }
222	
223	        $this->requestStartedAt->setTimezone($this->app['config']->get('app.timezone') ?? 'UTC');
224	
225	        foreach ($this->requestLifecycleDurationHandlers as ['threshold' => $threshold, 'handler' => $handler]) {
226	            $end ??= Carbon::now();
227	
228	            if ($this->requestStartedAt->diffInMilliseconds($end) > $threshold) {
229	                $handler($this->requestStartedAt, $request, $response);
230	            }
231	        }
232	
233	        $this->requestStartedAt = null;
234	    }
235	
236	    /**
237	     * Call the terminate method on any terminable middleware.
238	     *
239	     * @param  \Illuminate\Http\Request  $request
240	     * @param  \Illuminate\Http\Response  $response
241	     * @return void
242	     */
243	    protected function terminateMiddleware($request, $response)
244	    {
245	        $middlewares = $this->app->shouldSkipMiddleware() ? [] : array_merge(
246	            $this->gatherRouteMiddleware($request),
247	            $this->middleware
248	        );
249	
250	        foreach ($middlewares as $middleware) {
251	            if (! is_string($middleware)) {
252	                continue;
253	            }
254	
255	            [$name] = $this->parseMiddleware($middleware);
256	
257	            $instance = $this->app->make($name);
258	
259	            if (method_exists($instance, 'terminate')) {
260	                $instance->terminate($request, $response);
261	            }
262	        }
263	    }
264	
265	    /**
266	     * Register a callback to be invoked when the requests lifecycle duration exceeds a given amount of time.
267	     *
268	     * @param  \DateTimeInterface|\Carbon\CarbonInterval|float|int  $threshold
269	     * @param  callable  $handler
270	     * @return void
271	     */
272	    public function whenRequestLifecycleIsLongerThan($threshold, $handler)
273	    {
274	        $threshold = $threshold instanceof DateTimeInterface
275	            ? $this->secondsUntil($threshold) * 1000
276	            : $threshold;
277	
278	        $threshold = $threshold instanceof CarbonInterval
279	            ? $threshold->totalMilliseconds
280	            : $threshold;
281	
282	        $this->requestLifecycleDurationHandlers[] = [
283	            'threshold' => $threshold,
284	            'handler' => $handler,
285	        ];
286	    }
287	
288	    /**
289	     * When the request being handled started.
290	     *
291	     * @return \Illuminate\Support\Carbon|null
292	     */
293	    public function requestStartedAt()
294	    {
295	        return $this->requestStartedAt;
296	    }
