298	    /**
299	     * Gather the route middleware for the given request.
300	     *
301	     * @param  \Illuminate\Http\Request  $request
302	     * @return array
303	     */
304	    protected function gatherRouteMiddleware($request)
305	    {
306	        if ($route = $request->route()) {
307	            return $this->router->gatherRouteMiddleware($route);
308	        }
309	
310	        return [];
311	    }
312	
313	    /**
314	     * Parse a middleware string to get the name and parameters.
315	     *
316	     * @param  string  $middleware
317	     * @return array
318	     */
319	    protected function parseMiddleware($middleware)
320	    {
321	        [$name, $parameters] = array_pad(explode(':', $middleware, 2), 2, []);
322	
323	        if (is_string($parameters)) {
324	            $parameters = explode(',', $parameters);
325	        }
326	
327	        return [$name, $parameters];
328	    }
329	
330	    /**
331	     * Determine if the kernel has a given middleware.
332	     *
333	     * @param  string  $middleware
334	     * @return bool
335	     */
336	    public function hasMiddleware($middleware)
337	    {
338	        return in_array($middleware, $this->middleware);
339	    }
340	
341	    /**
342	     * Add a new middleware to the beginning of the stack if it does not already exist.
343	     *
344	     * @param  string  $middleware
345	     * @return $this
346	     */
347	    public function prependMiddleware($middleware)
348	    {
349	        if (array_search($middleware, $this->middleware) === false) {
350	            array_unshift($this->middleware, $middleware);
351	        }
352	
353	        return $this;
354	    }
355	
356	    /**
357	     * Add a new middleware to end of the stack if it does not already exist.
358	     *
359	     * @param  string  $middleware
360	     * @return $this
361	     */
362	    public function pushMiddleware($middleware)
363	    {
364	        if (array_search($middleware, $this->middleware) === false) {
365	            $this->middleware[] = $middleware;
366	        }
367	
368	        return $this;
369	    }
370	
371	    /**
372	     * Prepend the given middleware to the given middleware group.
373	     *
374	     * @param  string  $group
375	     * @param  string  $middleware
376	     * @return $this
377	     *
378	     * @throws \InvalidArgumentException
379	     */
380	    public function prependMiddlewareToGroup($group, $middleware)
381	    {
382	        if (! isset($this->middlewareGroups[$group])) {
383	            throw new InvalidArgumentException("The [{$group}] middleware group has not been defined.");
384	        }
385	
386	        if (array_search($middleware, $this->middlewareGroups[$group]) === false) {
387	            array_unshift($this->middlewareGroups[$group], $middleware);
388	        }
389	
390	        $this->syncMiddlewareToRouter();
391	
392	        return $this;
393	    }
394	
395	    /**
396	     * Append the given middleware to the given middleware group.
397	     *
398	     * @param  string  $group
399	     * @param  string  $middleware
400	     * @return $this
401	     *
402	     * @throws \InvalidArgumentException
403	     */
404	    public function appendMiddlewareToGroup($group, $middleware)
405	    {
406	        if (! isset($this->middlewareGroups[$group])) {
407	            throw new InvalidArgumentException("The [{$group}] middleware group has not been defined.");
408	        }
409	
410	        if (array_search($middleware, $this->middlewareGroups[$group]) === false) {
411	            $this->middlewareGroups[$group][] = $middleware;
412	        }
413	
414	        $this->syncMiddlewareToRouter();
415	
416	        return $this;
417	    }
418	
419	    /**
420	     * Prepend the given middleware to the middleware priority list.
421	     *
422	     * @param  string  $middleware
423	     * @return $this
424	     */
425	    public function prependToMiddlewarePriority($middleware)
426	    {
427	        if (! in_array($middleware, $this->middlewarePriority)) {
428	            array_unshift($this->middlewarePriority, $middleware);
429	        }
430	
431	        $this->syncMiddlewareToRouter();
432	
433	        return $this;
434	    }
435	
436	    /**
437	     * Append the given middleware to the middleware priority list.
438	     *
439	     * @param  string  $middleware
440	     * @return $this
441	     */
442	    public function appendToMiddlewarePriority($middleware)
443	    {
444	        if (! in_array($middleware, $this->middlewarePriority)) {
445	            $this->middlewarePriority[] = $middleware;
446	        }
447	
448	        $this->syncMiddlewareToRouter();
449	
450	        return $this;
451	    }
