837	    /**
838	     * Resolve a flat array of middleware classes from the provided array.
839	     *
840	     * @param  array  $middleware
841	     * @param  array  $excluded
842	     * @return array
843	     */
844	    public function resolveMiddleware(array $middleware, array $excluded = [])
845	    {
846	        $excluded = $excluded === []
847	            ? $excluded
848	            : (new Collection($excluded))
849	                ->map(fn ($name) => (array) MiddlewareNameResolver::resolve($name, $this->middleware, $this->middlewareGroups))
850	                ->flatten()
851	                ->values()
852	                ->all();
853	
854	        $middleware = (new Collection($middleware))
855	            ->map(fn ($name) => (array) MiddlewareNameResolver::resolve($name, $this->middleware, $this->middlewareGroups))
856	            ->flatten()
857	            ->when(
858	                ! empty($excluded),
859	                fn ($collection) => $collection->reject(function ($name) use ($excluded) {
860	                    if ($name instanceof Closure) {
861	                        return false;
862	                    }
863	
864	                    if (in_array($name, $excluded, true)) {
865	                        return true;
866	                    }
867	
868	                    if (! class_exists($name)) {
869	                        return false;
870	                    }
871	
872	                    $reflection = new ReflectionClass($name);
873	
874	                    return (new Collection($excluded))->contains(
875	                        fn ($exclude) => class_exists($exclude) && $reflection->isSubclassOf($exclude)
876	                    );
877	                })
878	            )
879	            ->values();
880	
881	        return $this->sortMiddleware($middleware);
882	    }
