15	    /**
16	     * The closure that resolves the permanent, static configuration if applicable.
17	     *
18	     * @var (Closure(Application): array<array-key, mixed>)|null
19	     */
20	    protected static ?Closure $alwaysUseConfig = null;
21	
22	    /**
23	     * Bootstrap the given application.
24	     *
25	     * @param  \Illuminate\Contracts\Foundation\Application  $app
26	     * @return void
27	     */
28	    public function bootstrap(Application $app)
29	    {
30	        $items = [];
31	
32	        // First we will see if we have a cache configuration file. If we do, we'll load
33	        // the configuration items from that file so that it is very quick. Otherwise
34	        // we will need to spin through every configuration file and load them all.
35	        $loadedFromCache = false;
36	
37	        if (self::$alwaysUseConfig !== null) {
38	            $items = $app->call(self::$alwaysUseConfig);
39	
40	            $loadedFromCache = true;
41	        } elseif (file_exists($cached = $app->getCachedConfigPath())) {
42	            $items = require $cached;
43	
44	            $loadedFromCache = true;
45	        }
46	
47	        $app->instance('config_loaded_from_cache', $loadedFromCache);
48	
49	        // Next we will spin through all of the configuration files in the configuration
50	        // directory and load each one into the repository. This will make all of the
51	        // options available to the developer for use in various parts of this app.
52	        $app->instance('config', $config = new Repository($items));
53	
54	        if (! $loadedFromCache) {
55	            $this->loadConfigurationFiles($app, $config);
56	        }
57	
58	        // Finally, we will set the application's environment based on the configuration
59	        // values that were loaded. We will pass a callback which will be used to get
60	        // the environment in a web context where an "--env" switch is not present.
61	        $app->detectEnvironment(fn () => $config->get('app.env', 'production'));
62	
63	        $app->resolveEnvironmentUsing($app->environment(...));
64	
65	        date_default_timezone_set($config->get('app.timezone', 'UTC'));
66	
67	        mb_internal_encoding('UTF-8');
68	    }
69	
70	    /**
71	     * Load the configuration items from all of the files.
72	     *
73	     * @param  \Illuminate\Contracts\Foundation\Application  $app
74	     * @param  \Illuminate\Contracts\Config\Repository  $repository
75	     * @return void
76	     *
77	     * @throws \Exception
78	     */
79	    protected function loadConfigurationFiles(Application $app, RepositoryContract $repository)
80	    {
81	        $files = $this->getConfigurationFiles($app);
82	
83	        $shouldMerge = method_exists($app, 'shouldMergeFrameworkConfiguration')
84	            ? $app->shouldMergeFrameworkConfiguration()
85	            : true;
86	
87	        $base = $shouldMerge
88	            ? $this->getBaseConfiguration()
89	            : [];
90	
91	        foreach ((new Collection($base))->diffKeys($files) as $name => $config) {
92	            $repository->set($name, $config);
93	        }
94	
95	        foreach ($files as $name => $path) {
96	            $base = $this->loadConfigurationFile($repository, $name, $path, $base);
97	        }
98	
99	        foreach ($base as $name => $config) {
100	            $repository->set($name, $config);
101	        }
102	    }
103	
104	    /**
105	     * Load the given configuration file.
106	     *
107	     * @param  \Illuminate\Contracts\Config\Repository  $repository
108	     * @param  string  $name
109	     * @param  string  $path
110	     * @param  array  $base
111	     * @return array
112	     */
113	    protected function loadConfigurationFile(RepositoryContract $repository, $name, $path, array $base)
114	    {
115	        $config = (fn () => require $path)();
116	
117	        if (isset($base[$name])) {
118	            $config = array_merge($base[$name], $config);
119	
120	            foreach ($this->mergeableOptions($name) as $option) {
121	                if (isset($config[$option])) {
122	                    $config[$option] = array_merge($base[$name][$option], $config[$option]);
123	                }
