133	
134	    /**
135	     * Get the options within the configuration file that should be merged again.
136	     *
137	     * @param  string  $name
138	     * @return array
139	     */
140	    protected function mergeableOptions($name)
141	    {
142	        return [
143	            'auth' => ['guards', 'providers', 'passwords'],
144	            'broadcasting' => ['connections'],
145	            'cache' => ['stores'],
146	            'database' => ['connections'],
147	            'filesystems' => ['disks'],
148	            'logging' => ['channels'],
149	            'mail' => ['mailers'],
150	            'queue' => ['connections'],
151	        ][$name] ?? [];
152	    }
153	
154	    /**
155	     * Get all of the configuration files for the application.
156	     *
157	     * @param  \Illuminate\Contracts\Foundation\Application  $app
158	     * @return array
159	     */
160	    protected function getConfigurationFiles(Application $app)
161	    {
162	        $files = [];
163	
164	        $configPath = realpath($app->configPath());
165	
166	        if (! $configPath) {
167	            return [];
168	        }
169	
170	        foreach (Finder::create()->files()->name('*.php')->in($configPath) as $file) {
171	            $directory = $this->getNestedDirectory($file, $configPath);
172	
173	            $files[$directory.basename($file->getRealPath(), '.php')] = $file->getRealPath();
174	        }
175	
176	        ksort($files, SORT_NATURAL);
177	
178	        return $files;
179	    }
180	
181	    /**
182	     * Get the configuration file nesting path.
183	     *
184	     * @param  \SplFileInfo  $file
185	     * @param  string  $configPath
186	     * @return string
187	     */
188	    protected function getNestedDirectory(SplFileInfo $file, $configPath)
189	    {
190	        $directory = $file->getPath();
191	
192	        if ($nested = trim(str_replace($configPath, '', $directory), DIRECTORY_SEPARATOR)) {
193	            $nested = str_replace(DIRECTORY_SEPARATOR, '.', $nested).'.';
194	        }
195	
196	        return $nested;
197	    }
198	
199	    /**
