207	
208	        foreach (Finder::create()->files()->name('*.php')->in(__DIR__.'/../../../../config') as $file) {
209	            $config[basename($file->getRealPath(), '.php')] = require $file->getRealPath();
210	        }
211	
212	        return $config;
213	    }
214	
215	    /**
