217	     *
218	     * @param  (Closure(Application): array<array-key, mixed>)|null  $alwaysUseConfig
219	     * @return void
220	     */
221	    public static function alwaysUse(?Closure $alwaysUseConfig): void
222	    {
223	        static::$alwaysUseConfig = $alwaysUseConfig;
224	    }
