13	class Pipeline implements PipelineContract
14	{
15	    use Conditionable;
16	    use Macroable;
17	
18	    /**
19	     * The container implementation.
20	     *
21	     * @var \Illuminate\Contracts\Container\Container|null
22	     */
23	    protected $container;
24	
25	    /**
26	     * The object being passed through the pipeline.
27	     *
28	     * @var mixed
29	     */
30	    protected $passable;
31	
32	    /**
33	     * The array of class pipes.
34	     *
35	     * @var array
36	     */
37	    protected $pipes = [];
38	
39	    /**
40	     * The method to call on each pipe.
41	     *
42	     * @var string
43	     */
44	    protected $method = 'handle';
45	
46	    /**
47	     * The final callback to be executed after the pipeline ends regardless of the outcome.
48	     *
49	     * @var \Closure|null
50	     */
51	    protected $finally;
52	
53	    /**
54	     * Indicates whether to wrap the pipeline in a database transaction.
55	     *
56	     * @var string|null|\UnitEnum|false
57	     */
58	    protected $withinTransaction = false;
59	
60	    /**
61	     * Create a new class instance.
62	     *
63	     * @param  \Illuminate\Contracts\Container\Container|null  $container
64	     */
65	    public function __construct(?Container $container = null)
66	    {
67	        $this->container = $container;
68	    }
69	
70	    /**
71	     * Set the object being sent through the pipeline.
72	     *
73	     * @param  mixed  $passable
74	     * @return $this
