86	     * @param  mixed  $pipes
87	     * @return $this
88	     */
89	    public function through($pipes)
90	    {
91	        $this->pipes = is_array($pipes) ? $pipes : func_get_args();
92	
93	        return $this;
94	    }
95	
96	    /**
97	     * Push additional pipes onto the pipeline.
98	     *
99	     * @param  mixed  $pipes
100	     * @return $this
101	     */
102	    public function pipe($pipes)
103	    {
104	        array_push($this->pipes, ...(is_array($pipes) ? $pipes : func_get_args()));
105	
106	        return $this;
107	    }
108	
109	    /**
110	     * Set the method to call on the pipes.
111	     *
112	     * @param  string  $method
113	     * @return $this
114	     */
115	    public function via($method)
116	    {
117	        $this->method = $method;
118	
119	        return $this;
120	    }
121	
122	    /**
123	     * Run the pipeline with a final destination callback.
124	     *
125	     * @param  \Closure  $destination
126	     * @return mixed
127	     */
128	    public function then(Closure $destination)
129	    {
130	        $pipeline = array_reduce(
131	            array_reverse($this->pipes()), $this->carry(), $this->prepareDestination($destination)
132	        );
133	
134	        try {
135	            return $this->withinTransaction !== false
136	                ? $this->getContainer()->make('db')->connection($this->withinTransaction)->transaction(fn () => $pipeline($this->passable))
137	                : $pipeline($this->passable);
138	        } finally {
139	            if ($this->finally) {
140	                ($this->finally)($this->passable);
141	            }
142	        }
143	    }
144	
145	    /**
146	     * Run the pipeline and return the result.
147	     *
148	     * @return mixed
149	     */
150	    public function thenReturn()
151	    {
152	        return $this->then(function ($passable) {
153	            return $passable;
154	        });
155	    }
156	
157	    /**
158	     * Set a final callback to be executed after the pipeline ends regardless of the outcome.
159	     *
160	     * @param  \Closure  $callback
161	     * @return $this
162	     */
163	    public function finally(Closure $callback)
164	    {
165	        $this->finally = $callback;
166	
167	        return $this;
168	    }
169	
170	    /**
171	     * Get the final piece of the Closure onion.
172	     *
173	     * @param  \Closure  $destination
174	     * @return \Closure
175	     */
176	    protected function prepareDestination(Closure $destination)
177	    {
178	        return function ($passable) use ($destination) {
179	            try {
180	                return $destination($passable);
181	            } catch (Throwable $e) {
182	                return $this->handleException($passable, $e);
183	            }
184	        };
185	    }
186	
187	    /**
188	     * Get a Closure that represents a slice of the application onion.
189	     *
190	     * @return \Closure
191	     */
192	    protected function carry()
193	    {
194	        return function ($stack, $pipe) {
195	            return function ($passable) use ($stack, $pipe) {
196	                try {
197	                    if (is_callable($pipe)) {
198	                        // If the pipe is a callable, then we will call it directly, but otherwise we
199	                        // will resolve the pipes out of the dependency container and call it with
200	                        // the appropriate method and arguments, returning the results back out.
201	                        return $pipe($passable, $stack);
202	                    } elseif (! is_object($pipe)) {
203	                        [$name, $parameters] = $this->parsePipeString($pipe);
204	
205	                        // If the pipe is a string we will parse the string and resolve the class out
206	                        // of the dependency injection container. We can then build a callable and
207	                        // execute the pipe function giving in the parameters that are required.
208	                        $pipe = $this->getContainer()->make($name);
209	
210	                        $parameters = array_merge([$passable, $stack], $parameters);
211	                    } else {
212	                        // If the pipe is already an object we'll just make a callable and pass it to
213	                        // the pipe as-is. There is no need to do any extra parsing and formatting
214	                        // since the object we're given was already a fully instantiated object.
215	                        $parameters = [$passable, $stack];
216	                    }
217	
218	                    $carry = method_exists($pipe, $this->method)
219	                        ? $pipe->{$this->method}(...$parameters)
220	                        : $pipe(...$parameters);
221	
222	                    return $this->handleCarry($carry);
223	                } catch (Throwable $e) {
224	                    return $this->handleException($passable, $e);
225	                }
226	            };
227	        };
228	    }
229	
230	    /**
231	     * Parse full pipe string to get name and parameters.
232	     *
233	     * @param  string  $pipe
234	     * @return array
235	     */
236	    protected function parsePipeString($pipe)
237	    {
238	        [$name, $parameters] = array_pad(explode(':', $pipe, 2), 2, null);
239	
240	        if (! is_null($parameters)) {
241	            $parameters = explode(',', $parameters);
242	        } else {
243	            $parameters = [];
244	        }
245	
246	        return [$name, $parameters];
247	    }
248	
249	    /**
250	     * Get the array of configured pipes.
251	     *
252	     * @return array
253	     */
254	    protected function pipes()
255	    {
256	        return $this->pipes;
257	    }
258	
259	    /**
260	     * Execute each pipeline step within a database transaction.
261	     *
262	     * @param  string|null|\UnitEnum|false  $withinTransaction
263	     * @return $this
264	     */
265	    public function withinTransaction($withinTransaction = null)
266	    {
267	        $this->withinTransaction = $withinTransaction;
268	
269	        return $this;
270	    }
271	
272	    /**
273	     * Get the container instance.
274	     *
275	     * @return \Illuminate\Contracts\Container\Container
276	     *
277	     * @throws \RuntimeException
278	     */
279	    protected function getContainer()
280	    {
281	        if (! $this->container) {
282	            throw new RuntimeException('A container instance has not been passed to the Pipeline.');
283	        }
284	
285	        return $this->container;
286	    }
287	
288	    /**
289	     * Set the container instance.
290	     *
291	     * @param  \Illuminate\Contracts\Container\Container  $container
292	     * @return $this
293	     */
294	    public function setContainer(Container $container)
295	    {
296	        $this->container = $container;
297	
298	        return $this;
299	    }
300	
301	    /**
302	     * Handle the value returned from each pipe before passing it to the next.
303	     *
304	     * @param  mixed  $carry
305	     * @return mixed
306	     */
307	    protected function handleCarry($carry)
308	    {
309	        return $carry;
310	    }
311	
312	    /**
313	     * Handle the given exception.
314	     *
315	     * @param  mixed  $passable
316	     * @param  \Throwable  $e
317	     * @return mixed
318	     *
319	     * @throws \Throwable
320	     */
321	    protected function handleException($passable, Throwable $e)
322	    {
323	        throw $e;
324	    }
325	}
