3	namespace Illuminate\Routing;
4	
5	use Illuminate\Container\Util;
6	use Illuminate\Support\Arr;
7	use Illuminate\Support\Reflector;
8	use ReflectionClass;
9	use ReflectionFunctionAbstract;
10	use ReflectionMethod;
11	use ReflectionParameter;
12	use stdClass;
13	
14	trait ResolvesRouteDependencies
15	{
16	    /**
17	     * Resolve the object method's type-hinted dependencies.
18	     *
19	     * @param  array  $parameters
20	     * @param  object  $instance
21	     * @param  string  $method
22	     * @return array
23	     */
24	    protected function resolveClassMethodDependencies(array $parameters, $instance, $method)
25	    {
26	        if (! method_exists($instance, $method)) {
27	            return $parameters;
28	        }
29	
30	        return $this->resolveMethodDependencies(
31	            $parameters, new ReflectionMethod($instance, $method)
32	        );
33	    }
34	
35	    /**
36	     * Resolve the given method's type-hinted dependencies.
37	     *
38	     * @param  array  $parameters
39	     * @param  \ReflectionFunctionAbstract  $reflector
40	     * @return array
41	     */
42	    public function resolveMethodDependencies(array $parameters, ReflectionFunctionAbstract $reflector)
43	    {
44	        $instanceCount = 0;
45	
46	        $values = array_values($parameters);
47	
48	        $skippableValue = new stdClass;
49	
50	        foreach ($reflector->getParameters() as $key => $parameter) {
51	            $instance = $this->transformDependency($parameter, $parameters, $skippableValue);
52	
53	            if ($instance !== $skippableValue) {
54	                $instanceCount++;
55	
56	                $this->spliceIntoParameters($parameters, $key, $instance);
57	            } elseif (! isset($values[$key - $instanceCount]) &&
58	                      $parameter->isDefaultValueAvailable()) {
59	                $this->spliceIntoParameters($parameters, $key, $parameter->getDefaultValue());
60	            }
61	
62	            $this->container->fireAfterResolvingAttributeCallbacks($parameter->getAttributes(), $instance);
63	        }
64	
65	        return $parameters;
66	    }
67	
68	    /**
69	     * Attempt to transform the given parameter into a class instance.
70	     *
71	     * @param  \ReflectionParameter  $parameter
72	     * @param  array  $parameters
73	     * @param  object  $skippableValue
74	     * @return mixed
75	     */
76	    protected function transformDependency(ReflectionParameter $parameter, $parameters, $skippableValue)
77	    {
78	        if ($attribute = Util::getContextualAttributeFromDependency($parameter)) {
79	            return $this->container->resolveFromAttribute($attribute, $parameter);
80	        }
81	
82	        $className = Reflector::getParameterClassName($parameter);
83	
84	        // If the parameter has a type-hinted class, we will check to see if it is already in
85	        // the list of parameters. If it is we will just skip it as it is probably a model
86	        // binding and we do not want to mess with those; otherwise, we resolve it here.
87	        if ($className && ! $this->alreadyInParameters($className, $parameters)) {
88	            $isEnum = (new ReflectionClass($className))->isEnum();
89	
90	            return $parameter->isDefaultValueAvailable()
91	                ? ($isEnum ? $parameter->getDefaultValue() : null)
92	                : $this->container->make($className);
93	        }
94	
95	        return $skippableValue;
96	    }
97	
98	    /**
99	     * Determine if an object of the given class is in a list of parameters.
100	     *
101	     * @param  string  $class
102	     * @param  array  $parameters
103	     * @return bool
104	     */
105	    protected function alreadyInParameters($class, array $parameters)
106	    {
107	        return ! is_null(Arr::first($parameters, fn ($value) => $value instanceof $class));
108	    }
109	
110	    /**
111	     * Splice the given value into the parameter list.
112	     *
113	     * @param  array  $parameters
114	     * @param  string  $offset
115	     * @param  mixed  $value
116	     * @return void
117	     */
118	    protected function spliceIntoParameters(array &$parameters, $offset, $value)
119	    {
120	        array_splice(
121	            $parameters, $offset, 0, [$value]
122	        );
123	    }
124	}
